bsdf.throughput = vec3(0.0);
if (weight < M_FLOAT_EPS)
return;
bsdf.response = color * occlusion * weight * M_PI_INV;
if (roughness > 0.0)
bsdf.response *= orenNayarDiffuse(L, V, normal, 1.0, roughness);
